# CCAD-KD Experiments: Full, runnable code for three experiments with test harness
# NOTE: This script is designed to be self-contained and quick-testable.
# - Deep learning framework: PyTorch only (as required).
# - Additional libs for utilities: numpy, scikit-learn, tdigest, matplotlib, seaborn, tqdm, timm (optional), torchvision, pandas.
# - Optional heavy libs (guarded by try/except): open-clip-torch, imagecorruptions, torchmetrics.
# - Plots are saved as .pdf only, suitable for papers.
# - Test function completes quickly on CPU by using synthetic and FakeData datasets.

import os
import math
import json
import time
import random
import shutil
from dataclasses import dataclass
from typing import List, Tuple, Dict, Any, Optional

import numpy as np
import torch
import torch.nn as nn
import torch.nn.functional as F
from torch.utils.data import DataLoader, TensorDataset
import torchvision as tv
import matplotlib
matplotlib.use('Agg')
import matplotlib.pyplot as plt
import seaborn as sns

# Optional dependencies (guarded)
try:
    import timm
except Exception:
    timm = None
try:
    from tdigest import TDigest
except Exception:
    TDigest = None
try:
    from sklearn.decomposition import PCA
    from sklearn.cluster import MiniBatchKMeans
except Exception:
    PCA = None
    MiniBatchKMeans = None

# ======================================================================================
# Required libraries list
# ======================================================================================
REQUIRED_LIBRARIES = [
    'torch', 'torchvision', 'numpy', 'matplotlib', 'seaborn', 'tdigest', 'scikit-learn', 'timm',
    'pandas', 'tqdm'
]
OPTIONAL_LIBRARIES = [
    'open-clip-torch', 'imagecorruptions', 'torchmetrics'
