# ======================================================================================
# Reproducibility and utilities
# ======================================================================================
def seed_all(seed: int = 42):
    random.seed(seed)
    np.random.seed(seed)
    torch.manual_seed(seed)
    torch.cuda.manual_seed_all(seed)


def get_device():
    return 'cuda' if torch.cuda.is_available() else 'cpu'


def ensure_dir(path: str):
    if path and not os.path.exists(path):
        os.makedirs(path, exist_ok=True)


def save_pdf(fig, filename: str):
    ensure_dir(os.path.dirname(filename) or '.')
    fig.savefig(filename, bbox_inches='tight')
    plt.close(fig)


# ======================================================================================
# CCAD Core Components
# ======================================================================================
class ECDFStore:
    """Per-context ECDF store using t-digest. Falls back to global when context counts are small.
    If tdigest is unavailable, uses a reservoir buffer per context and numpy quantiles.
    """
    def __init__(self, max_contexts: int = 1024, min_count: int = 64, eps: float = 1e-4, reservoir_size: int = 512):
        self.use_tdigest = TDigest is not None
        self.max_contexts = max_contexts
        self.min_count = min_count
        self.eps = eps
        self.counts: Dict[Any, int] = {}
        self.ctx_store: Dict[Any, Any] = {}
        self.global_store: Any
        self.reservoir_size = reservoir_size
        if self.use_tdigest:
            self.global_store = TDigest()
        else:
            self.global_store = []  # list of margins

    def _evict_if_needed(self, ctx_id: Any):
        if ctx_id in self.ctx_store:
            return
        if len(self.ctx_store) < self.max_contexts:
            return
        # Evict least frequent
        drop = min(self.counts, key=self.counts.get)
        self.ctx_store.pop(drop, None)
        self.counts.pop(drop, None)

    def update_many(self, ctx_ids: List[Any], margins: torch.Tensor):
        mv = margins.detach().cpu().float().numpy()
        if self.use_tdigest:
            self.global_store.batch_update(mv.tolist())
        else:
            if len(self.global_store) >= 100000:
                self.global_store = self.global_store[len(self.global_store)//2:]
            self.global_store.extend(mv.tolist())
        # per context
        by_ctx: Dict[Any, List[int]] = {}
        for i, c in enumerate(ctx_ids):
            by_ctx.setdefault(c, []).append(i)
        for c, idxs in by_ctx.items():
            self._evict_if_needed(c)
            vals = mv[idxs]
            if c not in self.ctx_store:
                if self.use_tdigest:
                    self.ctx_store[c] = TDigest()
                else:
                    self.ctx_store[c] = []
                self.counts[c] = 0
            if self.use_tdigest:
                self.ctx_store[c].batch_update(vals.tolist())
            else:
                buf = self.ctx_store[c]
                # reservoir sampling to bound memory
                for v in vals.tolist():
                    if len(buf) < self.reservoir_size:
                        buf.append(v)
                    else:
                        j = random.randint(0, self.counts[c])
                        if j < self.reservoir_size:
                            buf[j] = v
            self.counts[c] += len(vals)

    def quantiles(self, ctx_ids: List[Any], margins: torch.Tensor) -> Tuple[torch.Tensor, torch.Tensor]:
        mv = margins.detach().cpu().float().numpy()
        if self.use_tdigest:
            q_ref = np.array([self.global_store.cdf(float(v)) for v in mv])
        else:
            if len(self.global_store) == 0:
                q_ref = np.full_like(mv, 0.5)
            else:
                g = np.array(self.global_store)
                q_ref = np.array([float((g <= v).mean()) for v in mv])
        q_t = []
        for i, c in enumerate(ctx_ids):
            if c in self.ctx_store and self.counts.get(c, 0) >= self.min_count:
                if self.use_tdigest:
                    q_t.append(self.ctx_store[c].cdf(float(mv[i])))
                else:
                    buf = np.array(self.ctx_store[c])
                    if len(buf) == 0:
                        q_t.append(q_ref[i])
                    else:
                        q_t.append(float((buf <= mv[i]).mean()))
            else:
                q_t.append(q_ref[i])
        q_t = np.clip(np.array(q_t), self.eps, 1 - self.eps)
        q_ref = np.clip(q_ref, self.eps, 1 - self.eps)
        device = margins.device
        return torch.tensor(q_t, device=device, dtype=torch.float32), torch.tensor(q_ref, device=device, dtype=torch.float32)


class DROWeights:
    def __init__(self, eta: float = 0.1, clip: Tuple[float, float] = (0.25, 4.0), momentum: float = 0.9):
        self.eta = eta
        self.clip = clip
        self.momentum = momentum
        self.loss_ma: Dict[Any, float] = {}
        self.alpha_log: Dict[Any, float] = {}
        self.cached: Dict[Any, float] = {}

    def update(self, ctx_ids: List[Any], losses: torch.Tensor):
        by_ctx: Dict[Any, List[float]] = {}
        for c, l in zip(ctx_ids, losses.detach().cpu().tolist()):
            by_ctx.setdefault(c, []).append(float(l))
        for c, ls in by_ctx.items():
            avg = float(np.mean(ls))
            if c not in self.loss_ma:
                self.loss_ma[c] = avg
                self.alpha_log[c] = 0.0
            else:
                self.loss_ma[c] = self.momentum * self.loss_ma[c] + (1 - self.momentum) * avg
        if len(self.loss_ma) == 0:
            return
        mean_loss = float(np.mean(list(self.loss_ma.values())))
        for c in self.loss_ma:
            self.alpha_log[c] += self.eta * (self.loss_ma[c] - mean_loss)
        keys = list(self.alpha_log.keys())
        a = np.array([self.alpha_log[k] for k in keys])
        w = np.exp(a - a.max())
        w = w / (w.sum() + 1e-12)
        w = np.clip(w, self.clip[0], self.clip[1])
        w = w / (w.sum() + 1e-12)
        self.cached = {k: float(w[i]) for i, k in enumerate(keys)}

    def get(self, ctx_ids: List[Any]) -> torch.Tensor:
        if len(self.cached) == 0:
            return torch.ones(len(ctx_ids), dtype=torch.float32)
        return torch.tensor([self.cached.get(c, 1.0) for c in ctx_ids], dtype=torch.float32)


class QET:
    """Quantile-Equalized Teacher: per-context affine logits transform with moment matching."""
    def __init__(self, reg: float = 1e-3, ema: float = 0.99):
        self.s: Dict[Any, float] = {}
        self.b: Dict[Any, float] = {}
        self.reg = reg
        self.ema = ema

    def transform_batch(self, ctx_ids: List[Any], logits: torch.Tensor) -> torch.Tensor:
        device = logits.device
        s = torch.tensor([self.s.get(c, 1.0) for c in ctx_ids], device=device, dtype=logits.dtype).view(-1, 1)
        b = torch.tensor([self.b.get(c, 0.0) for c in ctx_ids], device=device, dtype=logits.dtype).view(-1, 1)
        return logits * s + b

    def update(self, ctx_ids: List[Any], margins_ctx: torch.Tensor, margins_global: torch.Tensor):
        by_ctx: Dict[Any, List[int]] = {}
        for i, c in enumerate(ctx_ids):
            by_ctx.setdefault(c, []).append(i)
        for c, idx in by_ctx.items():
            if len(idx) < 16:
                continue
            mc = margins_ctx[idx].detach().cpu().numpy()
            mg = margins_global[idx].detach().cpu().numpy()
            mc_mean, mc_std = mc.mean(), mc.std() + 1e-6
            mg_mean, mg_std = mg.mean(), mg.std() + 1e-6
            target_s = mg_std / mc_std
            target_b = mg_mean - target_s * mc_mean
            s = self.s.get(c, 1.0)
            b = self.b.get(c, 0.0)
            s = self.ema * s + (1 - self.ema) * target_s
            b = self.ema * b + (1 - self.ema) * target_b
            # Regularize toward s=1, b=0
            s = s - (1 - self.ema) * self.reg * (s - 1)
            b = b - (1 - self.ema) * self.reg * (b)
            self.s[c] = float(s)
            self.b[c] = float(b)


class KDComponents:
    def __init__(self, T_min: float = 2.0, T_max: float = 8.0, gamma: float = 1.2, beta: float = 1.5, delta: float = 1e-3, w_clip: Tuple[float, float] = (0.25, 4.0)):
        self.T_min = T_min
        self.T_max = T_max
        self.gamma = gamma
        self.beta = beta
        self.delta = delta
        self.w_clip = w_clip

    def adaptive_T(self, q_t: torch.Tensor) -> torch.Tensor:
        T = self.T_min + (self.T_max - self.T_min) * (1.0 - q_t).pow(self.gamma)
        return torch.clamp(T, min=self.T_min, max=self.T_max)

    def w_ctx(self, q_t: torch.Tensor, q_ref: torch.Tensor) -> torch.Tensor:
        w = ((q_ref + self.delta) / (q_t + self.delta)).pow(self.beta)
        return torch.clamp(w, self.w_clip[0], self.w_clip[1])


@torch.no_grad()
def teacher_margins(logits: torch.Tensor) -> torch.Tensor:
    top2 = torch.topk(logits, k=2, dim=-1).values
    return top2[:, 0] - top2[:, 1]


# ======================================================================================
# Augmentation logging and Context Manager
# ======================================================================================
@dataclass
class AugMeta:
    brightness: float
    contrast: float
    saturation: float
    crop_scale: float
    translation: float
    blur_sigma: float


class RandAugLogger:
    """Simple stochastic augmentation with parameter logging (approximate).
    Designed for CIFAR/ImageNet sized images. Uses torchvision functional ops.
    """
    def __init__(self, img_size: int = 224, blur_prob: float = 0.5):
        import torchvision.transforms.functional as TF
        self.TF = TF
        self.img_size = img_size
        self.blur_prob = blur_prob
        self.gauss_blur = tv.transforms.GaussianBlur(kernel_size=23, sigma=(0.1, 2.0))

    def __call__(self, img):
        # Resize to fixed square
        img = self.TF.resize(img, [self.img_size, self.img_size])
        # Random color params
        brightness = random.uniform(1 - 0.4, 1 + 0.4)
        contrast = random.uniform(1 - 0.4, 1 + 0.4)
        saturation = random.uniform(1 - 0.4, 1 + 0.4)
        img = self.TF.adjust_brightness(img, brightness)
        img = self.TF.adjust_contrast(img, contrast)
        img = self.TF.adjust_saturation(img, saturation)
        # Crop scale proxy (not exact RFCrop, but sufficient for context ID)
        crop_scale = random.uniform(0.3, 1.0)
        # Translation proxy
        translation = random.uniform(0.0, 0.2)
        # Blur
        blur_sigma = 0.0
        if random.random() < self.blur_prob:
            blur_sigma = random.uniform(0.1, 2.0)
            img = self.gauss_blur(img)
        # To tensor
        img = self.TF.to_tensor(img)
        meta = AugMeta(brightness=brightness, contrast=contrast, saturation=saturation,
                       crop_scale=crop_scale, translation=translation, blur_sigma=blur_sigma)
        return img, meta


class SimpleCNNFeaturizer(nn.Module):
    """Lightweight, random-weight conv feature extractor for style clustering fallback (no training)."""
    def __init__(self, out_dim: int = 128):
        super().__init__()
        self.conv = nn.Sequential(
            nn.Conv2d(3, 16, 3, stride=2, padding=1), nn.ReLU(),
            nn.Conv2d(16, 32, 3, stride=2, padding=1), nn.ReLU(),
            nn.Conv2d(32, 64, 3, stride=2, padding=1), nn.ReLU(),
            nn.AdaptiveAvgPool2d((1, 1))
        )
        self.fc = nn.Linear(64, out_dim)
        for p in self.parameters():
            p.requires_grad = False

    def forward(self, x):
        h = self.conv(x)
        h = h.view(h.size(0), -1)
        z = self.fc(h)
        z = F.normalize(z, dim=-1)
        return z


class StyleClusterer:
    """Flexible style clustering: prefers CLIP/DINO (if available), else uses SimpleCNNFeaturizer.
    Features are PCA-reduced (if sklearn present) and clustered with MiniBatchKMeans.
    """
    def __init__(self, device: str = 'cpu', pca_dim: int = 64, n_clusters: int = 8, fit_max_samples: int = 50000):
        self.device = device
        self.pca_dim = pca_dim
        self.n_clusters = n_clusters
        self.fit_max_samples = fit_max_samples
        self.pca = None
        self.kmeans = None
        self.mode = 'simple-cnn'
        self.featurizer = SimpleCNNFeaturizer(out_dim=256).to(device).eval()

    @torch.no_grad()
    def featurize_batch(self, imgs: torch.Tensor) -> np.ndarray:
        imgs = imgs.to(self.device)
        feats = self.featurizer(imgs)
        return feats.detach().cpu().numpy()

    def fit(self, loader: DataLoader, n_samples: int = 20000):
        if PCA is None or MiniBatchKMeans is None:
            print('[StyleClusterer] sklearn not available; using identity features and random clusters.')
            self.pca = None
            self.kmeans = None
            return
        X = []
        seen = 0
        for batch in loader:
            if isinstance(batch, (list, tuple)):
                imgs = batch[0]
            else:
                imgs = batch
            feats = self.featurize_batch(imgs)
            X.append(feats)
            seen += feats.shape[0]
            if seen >= n_samples:
                break
        X = np.concatenate(X, axis=0)
        n_comp = min(self.pca_dim, X.shape[1])
        self.pca = PCA(n_components=n_comp, random_state=0).fit(X)
        Xp = self.pca.transform(X)
        self.kmeans = MiniBatchKMeans(n_clusters=self.n_clusters, random_state=0, batch_size=4096).fit(Xp)
        print(f'[StyleClusterer] Fitted PCA({n_comp}) and KMeans(k={self.n_clusters}) on {Xp.shape[0]} samples.')

    @torch.no_grad()
    def predict_ids(self, imgs: torch.Tensor) -> List[int]:
        feats = self.featurize_batch(imgs)
        if self.pca is not None and self.kmeans is not None:
            Xp = self.pca.transform(feats)
            cids = self.kmeans.predict(Xp)
            return [int(c) for c in cids]
        # Fallback: hash of coarse feature for stable pseudo-clusters
        proj = (feats * 7.0).astype(np.int32)
        hashes = (proj.sum(axis=1) % max(1, self.n_clusters)).astype(int)
        return [int(h) for h in hashes]


class ContextManager:
    def __init__(self, style_clusterer: StyleClusterer, bin_edges: Dict[str, List[float]]):
        self.sc = style_clusterer
        self.bin_edges = bin_edges

    def _bin(self, v: float, edges: List[float]) -> int:
        return int(np.digitize([float(v)], edges)[0])  # returns 0..len(edges)

    def aug_to_str(self, meta: AugMeta) -> str:
        b = self._bin(meta.brightness, self.bin_edges['brightness'])
        c = self._bin(meta.contrast,   self.bin_edges['contrast'])
        s = self._bin(meta.saturation, self.bin_edges['saturation'])
        r = self._bin(meta.crop_scale, self.bin_edges['crop_scale'])
        t = self._bin(meta.translation, self.bin_edges['translation'])
        bl= self._bin(meta.blur_sigma, self.bin_edges['blur_sigma'])
        return f"b{b}|c{c}|s{s}|r{r}|t{t}|bl{bl}"

    @torch.no_grad()
    def batch_context_ids(self, metas: List[AugMeta], imgs: torch.Tensor) -> List[str]:
        style_ids = self.sc.predict_ids(imgs)
        out = []
        for m, sid in zip(metas, style_ids):
            aug_id = self.aug_to_str(m)
            out.append(f"{aug_id}||style:{sid}")
        return out


# ======================================================================================
# Metrics utilities
# ======================================================================================
@torch.no_grad()
def compute_ece(logits: torch.Tensor, targets: torch.Tensor, n_bins: int = 15) -> float:
    probs = F.softmax(logits, dim=-1)
    conf, preds = probs.max(dim=-1)
    targets = targets.view(-1)
    bin_edges = torch.linspace(0, 1, n_bins + 1)
    ece = 0.0
    total = float(len(targets)) + 1e-12
    for i in range(n_bins):
        mask = (conf >= bin_edges[i]) & (conf < bin_edges[i + 1])
        if mask.sum() > 0:
            acc = (preds[mask] == targets[mask]).float().mean().item()
            avg_conf = conf[mask].mean().item()
            weight = mask.float().mean().item()
            ece += abs(avg_conf - acc) * weight
    return float(ece)


@torch.no_grad()
def confusion_matrix(preds: torch.Tensor, targets: torch.Tensor, num_classes: int) -> np.ndarray:
    cm = np.zeros((num_classes, num_classes), dtype=np.int64)
    for p, t in zip(preds.cpu().numpy(), targets.cpu().numpy()):
        cm[int(t), int(p)] += 1
    return cm


def worst_group_accuracy(preds: torch.Tensor, targets: torch.Tensor, ctx_ids: List[Any], min_count: int = 25) -> float:
    from collections import defaultdict
    group = defaultdict(list)
    for i, c in enumerate(ctx_ids):
        group[c].append(i)
    wga = float('nan')
    accs = []
    for c, idx in group.items():
        if len(idx) < min_count:
            continue
        p = preds[idx]
        y = targets[idx]
        accs.append((p == y).float().mean().item())
    if len(accs) > 0:
        wga = float(min(accs))
    return wga


# ======================================================================================
# Generic KD Training Loop (supports CCAD and baselines)
# ======================================================================================
def kd_train_epoch(student: nn.Module,
                   teacher: nn.Module,
                   loader: DataLoader,
                   ctx_mgr: Optional[ContextManager],
                   ecdfs: ECDFStore,
                   dro: DROWeights,
                   qet: Optional[QET],
                   ccad: KDComponents,
                   optimizer: torch.optim.Optimizer,
                   device: str = 'cpu',
                   alpha_kd: float = 1.0,
                   warmup: bool = False,
                   base_T: float = 4.0,
                   enable_qet: bool = False,
                   backprop_ce: bool = True,
                   print_prefix: str = '') -> Dict[str, float]:
    student.train()
    teacher.eval()
    kd_losses, ce_losses, total_losses, grad_norms = [], [], [], []

    for imgs, labels, metas in loader:
        imgs = imgs.to(device)
        labels = labels.to(device)
        if ctx_mgr is not None:
            ctx_ids = ctx_mgr.batch_context_ids(metas, imgs)
        else:
            ctx_ids = ['global'] * imgs.shape[0]

        with torch.no_grad():
            t_logits = teacher(imgs)
            if enable_qet and (qet is not None) and not warmup:
                t_logits = qet.transform_batch(ctx_ids, t_logits)
            margins = teacher_margins(t_logits)

        if warmup:
            ecdfs.update_many(ctx_ids, margins)
            T = torch.full((imgs.shape[0],), base_T, device=device)
            w_ctx = torch.ones_like(T)
            a_t = torch.ones_like(T)
        else:
            q_t, q_ref = ecdfs.quantiles(ctx_ids, margins)
            T = ccad.adaptive_T(q_t)
            w_ctx = ccad.w_ctx(q_t, q_ref)
            a_t = dro.get(ctx_ids).to(device)

        optimizer.zero_grad(set_to_none=True)
        s_logits = student(imgs)
        # KD with per-sample T
        p_t = F.softmax(t_logits / T.view(-1, 1), dim=-1)
        log_p_t = F.log_softmax(t_logits / T.view(-1, 1), dim=-1)
        log_p_s = F.log_softmax(s_logits, dim=-1)
        kd_per = torch.sum(p_t * (log_p_t - log_p_s), dim=-1)
        kd_loss = (kd_per * w_ctx * a_t).mean()
        if backprop_ce:
            ce_loss = F.cross_entropy(s_logits, labels)
            loss = ce_loss + alpha_kd * kd_loss
        else:
            ce_loss = torch.tensor(0.0, device=device)
            loss = alpha_kd * kd_loss
        loss.backward()
        torch.nn.utils.clip_grad_norm_(student.parameters(), 1.0)
        optimizer.step()
        if not warmup:
            dro.update(ctx_ids, kd_per.detach())
            if qet is not None and enable_qet:
                qet.update(ctx_ids, teacher_margins(t_logits.detach()), margins.detach())

        kd_losses.append(kd_loss.item())
        ce_losses.append(ce_loss.item() if isinstance(ce_loss, torch.Tensor) else float(ce_loss))
        total_losses.append(loss.item())

    out = {
        'kd_loss': float(np.mean(kd_losses)) if len(kd_losses) else 0.0,
        'ce_loss': float(np.mean(ce_losses)) if len(ce_losses) else 0.0,
        'total_loss': float(np.mean(total_losses)) if len(total_losses) else 0.0,
    }
    print(f"{print_prefix} Train epoch done. KD loss: {out['kd_loss']:.4f}, CE loss: {out['ce_loss']:.4f}, Total: {out['total_loss']:.4f}")
    return out


@torch.no_grad()
def evaluate_model(model: nn.Module,
                   loader: DataLoader,
                   ctx_mgr: Optional[ContextManager] = None,
                   ecdfs: Optional[ECDFStore] = None,
                   device: str = 'cpu',
                   num_classes: int = None,
                   print_prefix: str = '') -> Dict[str, Any]:
    model.eval()
    all_logits, all_targets, all_ctx = [], [], []
    for imgs, labels, metas in loader:
        imgs = imgs.to(device)
        labels = labels.to(device)
        logits = model(imgs)
        all_logits.append(logits.cpu())
        all_targets.append(labels.cpu())
        if ctx_mgr is not None:
            ctx_ids = ctx_mgr.batch_context_ids(metas, imgs)
        else:
            ctx_ids = ['global'] * imgs.shape[0]
        all_ctx += ctx_ids
    logits = torch.cat(all_logits)
    targets = torch.cat(all_targets)
    preds = logits.argmax(dim=-1)
    acc = (preds == targets).float().mean().item()
    nll = F.cross_entropy(logits, targets).item()
    ece = compute_ece(logits, targets, n_bins=15)
    wga = worst_group_accuracy(preds, targets, all_ctx, min_count=25)
    res = {'acc': acc, 'nll': nll, 'ece': ece, 'worst_group_acc': wga}
    if num_classes is None:
        num_classes = int(logits.shape[-1])
    cm = confusion_matrix(preds, targets, num_classes)
    res['confusion_matrix'] = cm
    print(f"{print_prefix} Eval: Acc={acc:.4f}, NLL={nll:.4f}, ECE={ece:.4f}, Worst-Group-Acc={wga:.4f}")
    return res


