    teacher.to(device).eval()
    student.to(device)

    # Initialize teacher randomly for dry_run to avoid heavy pretraining; that's fine for functionality test
    # Optimizer and components
    optimizer = torch.optim.SGD(student.parameters(), lr=0.05, momentum=0.9, weight_decay=5e-4)
    ecdfs = ECDFStore(max_contexts=512, min_count=32)
    dro = DROWeights(eta=0.1)
    qet = QET(reg=1e-3)
    ccad = KDComponents(T_min=2.0, T_max=7.0, gamma=1.2, beta=1.0)

    # Training schedule (short)
    train_hist = {'epoch': [], 'kd': [], 'ce': [], 'total': []}

    for epoch in range(max_epochs):
        warmup = epoch < warmup_epochs
        stats = kd_train_epoch(student, teacher, train_loader, ctx_mgr, ecdfs, dro, qet, ccad, optimizer,
                               device=device, alpha_kd=1.0, warmup=warmup, base_T=4.0,
                               enable_qet=(epoch >= 3), backprop_ce=True, print_prefix=f'[Exp1][Epoch {epoch+1}/{max_epochs}]')
        train_hist['epoch'].append(epoch)
        train_hist['kd'].append(stats['kd_loss'])
        train_hist['ce'].append(stats['ce_loss'])
        train_hist['total'].append(stats['total_loss'])

    # Evaluation
    eval_res = evaluate_model(student, test_loader, ctx_mgr, ecdfs, device=device, num_classes=num_classes, print_prefix='[Exp1]')

    # Plots
    # 1) Training loss curve
    fig, ax = plt.subplots(figsize=(4, 3))
    ax.plot(train_hist['epoch'], train_hist['total'], label='Total loss')
    ax.plot(train_hist['epoch'], train_hist['kd'], label='KD loss')
    ax.plot(train_hist['epoch'], train_hist['ce'], label='CE loss')
    ax.set_xlabel('Epoch')
    ax.set_ylabel('Loss')
    ax.legend()
    save_pdf(fig, os.path.join(outdir, 'training_loss_ccad.pdf'))
    print(f"[Exp1] Saved plot: {os.path.join(outdir, 'training_loss_ccad.pdf')}")

    # 2) Accuracy (single point bar)
    fig, ax = plt.subplots(figsize=(3, 3))
    ax.bar(['Top-1 acc'], [eval_res['acc']])
    ax.set_ylim(0, 1)
    save_pdf(fig, os.path.join(outdir, 'accuracy_ccad.pdf'))
    print(f"[Exp1] Saved plot: {os.path.join(outdir, 'accuracy_ccad.pdf')}")

    # 3) Confusion Matrix (may be large; show as heatmap with small font)
    cm = eval_res['confusion_matrix']
    fig, ax = plt.subplots(figsize=(5, 4))
    sns.heatmap(cm / (cm.sum(axis=1, keepdims=True) + 1e-9), cmap='viridis', cbar=True, ax=ax)
    ax.set_title('Confusion Matrix (row-normalized)')
    ax.set_xlabel('Predicted'); ax.set_ylabel('True')
    save_pdf(fig, os.path.join(outdir, 'confusion_matrix_ccad.pdf'))
    print(f"[Exp1] Saved plot: {os.path.join(outdir, 'confusion_matrix_ccad.pdf')}")

    print('[Exp1] Final metrics:', json.dumps({k: float(v) if isinstance(v, (int, float)) else None for k, v in eval_res.items() if k != 'confusion_matrix'}, indent=2))
    return eval_res


