def build_imagenet100_dataloaders(data_root: str = './imagenet', batch_size: int = 128, img_size: int = 224, dry_run: bool = True,
                                  n_train: int = 1024, n_val: int = 256) -> Tuple[DataLoader, DataLoader]:
    tf_train = RandAugLogger(img_size=img_size)
    tf_val = tv.transforms.Compose([tv.transforms.Resize(img_size), tv.transforms.ToTensor()])
    if dry_run:
        train_set = tv.datasets.FakeData(size=n_train, image_size=(3, img_size, img_size), num_classes=100, transform=None)
        val_set = tv.datasets.FakeData(size=n_val, image_size=(3, img_size, img_size), num_classes=100, transform=tf_val)
    else:
        # Expect folder structure ImageNet-100 with 100 classes
        train_set = tv.datasets.ImageFolder(os.path.join(data_root, 'train'), transform=None)
        val_set = tv.datasets.ImageFolder(os.path.join(data_root, 'val'), transform=tf_val)

    def train_collate(batch):
        imgs, metas, labels = [], [], []
        for img, y in batch:
            img, meta = tf_train(img)
            imgs.append(img); metas.append(meta); labels.append(y)
        return torch.stack(imgs), torch.tensor(labels, dtype=torch.long), metas

    train_loader = DataLoader(train_set, batch_size=batch_size, shuffle=True, num_workers=2, collate_fn=train_collate)
    val_loader = DataLoader(val_set, batch_size=batch_size, shuffle=False, num_workers=2,
                            collate_fn=lambda batch: (
                                torch.stack([x[0] if isinstance(x[0], torch.Tensor) else tf_val(x[0]) for x in batch]),
                                torch.tensor([x[1] for x in batch], dtype=torch.long),
                                [AugMeta(1.0, 1.0, 1.0, 1.0, 0.0, 0.0) for _ in batch]
                            ))
    return train_loader, val_loader


