# Experiment 3: Synthetic 2D Context-Bias Toy (Mechanism + Early Stability)
# ======================================================================================
def make_toy(n_train: int = 8000, n_test: int = 2000, n_ctx: int = 4, n_classes: int = 3, seed: int = 0):
    rng = np.random.RandomState(seed)
    means = np.array([[0, 0], [3, 0], [0, 3]], dtype=float)
    cov = np.array([[0.6, 0.0], [0.0, 0.6]])

    def sample(n):
        Xs, ys, cs = [], [], []
        for i in range(n):
            y = int(rng.randint(n_classes))
            x = rng.multivariate_normal(means[y], cov)
            c = int(rng.randint(n_ctx))
            Xs.append(x); ys.append(y); cs.append(c)
        return np.array(Xs, np.float32), np.array(ys, np.int64), np.array(cs, np.int64)

    Xtr, Ytr, Ctr = sample(n_train)
    Xte, Yte, Cte = sample(n_test)
    return torch.from_numpy(Xtr), torch.from_numpy(Ytr), torch.from_numpy(Ctr), \
           torch.from_numpy(Xte), torch.from_numpy(Yte), torch.from_numpy(Cte)


class MLP(nn.Module):
    def __init__(self, d: int = 2, h: int = 64, k: int = 3):
        super().__init__()
        self.net = nn.Sequential(
            nn.Linear(d, h), nn.ReLU(), nn.Linear(h, k)
        )

    def forward(self, x):
        return self.net(x)


# Teacher bias per context
TOY_S = torch.tensor([0.5, 1.0, 1.5, 2.0], dtype=torch.float32)
TOY_B = torch.tensor([-0.3, 0.0, 0.2, 0.4], dtype=torch.float32)


def apply_teacher_bias(logits: torch.Tensor, ctx_ids: torch.Tensor) -> torch.Tensor:
    s = TOY_S[ctx_ids]
    b = TOY_B[ctx_ids]
    return logits * s.view(-1, 1) + b.view(-1, 1)


def run_experiment3_toy_ccad(max_epochs: int = 10, warmup_epochs: int = 2, outdir: str = './figs_exp3'):
    print('=== Experiment 3: Synthetic 2D Context-Bias Toy (CCAD) ===')
    device = get_device()
    seed_all(7)
    ensure_dir(outdir)

    Xtr, Ytr, Ctr, Xte, Yte, Cte = make_toy(n_train=4000, n_test=1000)
    train_loader = DataLoader(TensorDataset(Xtr, Ytr, Ctr), batch_size=512, shuffle=True)
    test_loader = DataLoader(TensorDataset(Xte, Yte, Cte), batch_size=512, shuffle=False)

    teacher = MLP().to(device)
    # Train teacher briefly (no bias yet)
    opt_t = torch.optim.Adam(teacher.parameters(), lr=1e-3)
    teacher.train()
    for ep in range(50):
        for xb, yb, cb in train_loader:
            xb, yb = xb.to(device), yb.to(device)
            logits = teacher(xb)
            loss = F.cross_entropy(logits, yb)
            opt_t.zero_grad(); loss.backward(); opt_t.step()
    for p in teacher.parameters():
        p.requires_grad = False

    student = MLP().to(device)
    opt_s = torch.optim.Adam(student.parameters(), lr=1e-3)
    ecdfs = ECDFStore(min_count=64)
    dro = DROWeights(eta=0.1)
    qet = None
    ccad = KDComponents(T_min=2.0, T_max=6.0, gamma=1.0, beta=1.0)

    # Simple Context Manager for toy (wrap C as aug meta bins and style id identical for simplicity)
    class ToyCtxMgr:
        def batch_context_ids(self, metas, xb):
            # metas is a list of integers (context)
            return [f"toyctx:{int(m)}" for m in metas]

    ctx_mgr = ToyCtxMgr()

    # Build loaders that mimic (imgs, labels, metas) signature
    def toy_collate(batch):
        xs = torch.stack([b[0] for b in batch])
        ys = torch.stack([b[1] for b in batch])
        cs = [int(b[2].item()) for b in batch]
        return xs, ys, cs

    train_loader2 = DataLoader(TensorDataset(Xtr, Ytr, Ctr), batch_size=512, shuffle=True, collate_fn=toy_collate)
    test_loader2 = DataLoader(TensorDataset(Xte, Yte, Cte), batch_size=512, shuffle=False, collate_fn=toy_collate)

    hist = {'epoch': [], 'kd': [], 'total': []}
    for epoch in range(max_epochs):
        # Custom train loop for toy to apply bias
        student.train(); teacher.eval()
        kd_losses = []
        for xb, yb, cb in train_loader2:
            xb, yb = xb.to(device), yb.to(device)
            cb_t = torch.tensor(cb, dtype=torch.long, device=device)
            with torch.no_grad():
                t_logits = teacher(xb)
                t_logits = apply_teacher_bias(t_logits, cb_t)
                margins = teacher_margins(t_logits)
            if epoch < warmup_epochs:
                ecdfs.update_many(ctx_mgr.batch_context_ids(cb, xb), margins)
                T = torch.full((xb.shape[0],), 4.0, device=device)
                w = torch.ones_like(T); a_t = torch.ones_like(T)
            else:
                q_t, q_ref = ecdfs.quantiles(ctx_mgr.batch_context_ids(cb, xb), margins)
                T = ccad.adaptive_T(q_t)
                w = ccad.w_ctx(q_t, q_ref)
                a_t = dro.get(ctx_mgr.batch_context_ids(cb, xb)).to(device)
            opt_s.zero_grad(set_to_none=True)
            s_logits = student(xb)
            p_t = F.softmax(t_logits / T.view(-1, 1), dim=-1)
            log_p_t = F.log_softmax(t_logits / T.view(-1, 1), dim=-1)
            log_p_s = F.log_softmax(s_logits, dim=-1)
            kd_per = torch.sum(p_t * (log_p_t - log_p_s), dim=-1)
            loss = (kd_per * w * a_t).mean()  # no CE to stress KD
            loss.backward(); torch.nn.utils.clip_grad_norm_(student.parameters(), 1.0); opt_s.step()
            kd_losses.append(loss.item())
            if epoch >= warmup_epochs:
                dro.update(ctx_mgr.batch_context_ids(cb, xb), kd_per.detach())
        hist['epoch'].append(epoch)
        hist['kd'].append(float(np.mean(kd_losses)))
        hist['total'].append(float(np.mean(kd_losses)))
        print(f"[Exp3][Epoch {epoch+1}/{max_epochs}] KD loss: {hist['kd'][-1]:.4f}")

    # Evaluate on test
    @torch.no_grad()
    def eval_toy(model: nn.Module, loader: DataLoader) -> Dict[str, Any]:
        model.eval()
        all_logits, all_targets, all_ctx = [], [], []
        for xb, yb, cb in loader:
            xb, yb = xb.to(device), yb.to(device)
            logits = model(xb)
            all_logits.append(logits.cpu())
            all_targets.append(yb.cpu())
            all_ctx += [f"toyctx:{int(c)}" for c in cb]
        logits = torch.cat(all_logits)
        targets = torch.cat(all_targets)
        preds = logits.argmax(dim=-1)
        acc = (preds == targets).float().mean().item()
        nll = F.cross_entropy(logits, targets).item()
        ece = compute_ece(logits, targets, n_bins=15)
        wga = worst_group_accuracy(preds, targets, all_ctx, min_count=25)
        return {'acc': acc, 'nll': nll, 'ece': ece, 'worst_group_acc': wga}

    eval_res = eval_toy(student, test_loader2)
    print('[Exp3] Final metrics:', json.dumps(eval_res, indent=2))

    # Plots: training loss, accuracy bar, and (simulated) ECDF alignment for one context
    fig, ax = plt.subplots(figsize=(4, 3))
    ax.plot(hist['epoch'], hist['kd'], label='KD loss')
    ax.set_xlabel('Epoch'); ax.set_ylabel('Loss'); ax.legend()
    save_pdf(fig, os.path.join(outdir, 'training_loss_ccad.pdf'))
    print(f"[Exp3] Saved plot: {os.path.join(outdir, 'training_loss_ccad.pdf')}")

    fig, ax = plt.subplots(figsize=(3, 3))
    ax.bar(['Top-1 acc'], [eval_res['acc']]); ax.set_ylim(0, 1)
    save_pdf(fig, os.path.join(outdir, 'accuracy_ccad.pdf'))
    print(f"[Exp3] Saved plot: {os.path.join(outdir, 'accuracy_ccad.pdf')}")

    # Margin ECDF for a chosen context (e.g., ctx=0) comparing teacher vs student
    # We approximate student margins for visualization only
    ctx0_idx = (Cte == 0).nonzero(as_tuple=False).view(-1)
    with torch.no_grad():
        logits_t = teacher(Xte[ctx0_idx].to(device))
        logits_t = apply_teacher_bias(logits_t, torch.zeros_like(ctx0_idx, dtype=torch.long, device=device))
        margins_t = teacher_margins(logits_t).cpu().numpy()
        margins_s = teacher_margins(student(Xte[ctx0_idx].to(device))).cpu().numpy()
    mt = np.sort(margins_t)
    ms = np.sort(margins_s)
    Ft = np.linspace(0, 1, len(mt))
    Fs = np.linspace(0, 1, len(ms))
    fig, ax = plt.subplots(figsize=(4, 3))
    ax.plot(mt, Ft, label='Teacher ECDF (ctx0)')
    ax.plot(ms, Fs, label='Student ECDF (ctx0)')
    ax.set_xlabel('Margin'); ax.set_ylabel('ECDF'); ax.legend()
    save_pdf(fig, os.path.join(outdir, 'ecdf_margins_ccad.pdf'))
    print(f"[Exp3] Saved plot: {os.path.join(outdir, 'ecdf_margins_ccad.pdf')}")

    return eval_res


